from flask import Flask, render_template, redirect, request, session
from flask_oidc import OpenIDConnect
from cryptography.hazmat.primitives import serialization
from jwt import decode

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key'
app.config['OIDC_CLIENT_ID'] = 'client_id'
app.config['OIDC_CLIENT_SECRET'] = 'client_secret'
app.config['OIDC_PROVIDER_URL'] = 'provider_url'

oidc = OpenIDConnect(app)

@app.route('/')
def index():
    if oidc.is_authenticated():
        return render_template('index.html', user=oidc.user_info)
    else:
        return redirect(oidc.authorize_url)

@app.route('/callback')
def callback():
    token_response = oidc.callback()
    id_token = token_response.id_token
    payload = decode(id_token, key=oidc.client_secrets['client_secret'], algorithms=['RS256'])
    session['user_info'] = payload
    return redirect('/')

if __name__ == '__main__':
    app.run(debug=True)